//! Integration tests for ctx.call_tool()

use fastmcp_server::{Server, ServerBuilder};
use fastmcp_macros::tool;

#[tokio::test]
async fn test_tool_calls_another_tool() {
    #[tool]
    async fn add(a: i32, b: i32) -> i32 {
        a + b
    }

    #[tool]
    async fn double_add(ctx: &McpContext, a: i32, b: i32) -> Result<i32, ToolError> {
        let sum: i32 = ctx.call_tool_json("add", json!({"a": a, "b": b})).await?;
        Ok(sum * 2)
    }

    let server = ServerBuilder::new("test", "1.0")
        .tool(add)
        .tool(double_add)
        .build();

    let result = server.call_tool("double_add", json!({"a": 5, "b": 3})).await.unwrap();
    assert_eq!(result.content[0].as_text(), Some("16"));
}

