async fn test_chained_tool_calls() {
    #[tool]
    async fn step1() -> String { "step1".into() }

    #[tool]
    async fn step2(ctx: &McpContext) -> Result<String, ToolError> {
        let s1 = ctx.call_tool_text("step1", json!({})).await?;
